import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life", () => {
  it.todo("should return an empty set when given an empty set of living cells");
  it.todo("should kill a single living cell with no neighbors (underpopulation)");
  it.todo("should kill a living cell with only one live neighbor (underpopulation)");
  it.todo("should keep a living cell alive with two live neighbors (survival)");
  it.todo("should keep a living cell alive with three live neighbors (survival)");
  it.todo("should kill a living cell with four live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life with exactly three live neighbors (reproduction)");
  it.todo("should handle living cells with negative coordinates");
});
